// ENHANCED: Gemini API with Safety Filter Detection
const GEMINI_API_KEY = 'AIzaSyCu7cMyJAB4ossEePGYQQGpzjlqAfbIG2E';

const ctx = String($input.first().json.conversation_context || '').trim();

// Handle empty context
if (!ctx) {
  console.log('⚠️ No conversation context provided, returning default values');
  return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], api_used: 'default' } }];
}

const prompt = `You are a personality detector. Infer Big Five from the user text for THIS TURN ONLY. Return JSON ONLY exactly as: {"ocean_disc":{"O":-1|0|1,"C":-1|0|1,"E":-1|0|1,"A":-1|0|1,"N":-1|0|1}} No prose.\n\nText: ${ctx}`;

console.log('🚀 Calling Gemini API for OCEAN detection...');
console.log('📝 Prompt length:', prompt.length, 'characters');
console.log('🔗 Context:', ctx.substring(0, 100) + (ctx.length > 100 ? '...' : ''));

// ✅ CORRECTED: Using recommended model for reliability
const model = 'gemini-1.5-flash-latest';
const options = {
  method: 'POST',
  url: `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${GEMINI_API_KEY}`,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ // ✅ User's suggestion: explicit JSON.stringify
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { 
      temperature: 0.1, 
      maxOutputTokens: 200, 
      topK: 40, 
      topP: 0.95 
    },
    safetySettings: [
      { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
      { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
      { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
      { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' }
    ]
  }),
  timeout: 20000
};

try {
  const response = await this.helpers.httpRequest(options);

  console.log('📊 Raw Gemini Response:', JSON.stringify(response, null, 2));

  // ✅ IMPROVED: Check for candidates first
  if (response.candidates && response.candidates.length > 0) {
    const content = response.candidates[0].content.parts[0].text;
    console.log('✅ Gemini API successful');
    console.log('📝 Content received:', content);

    return [{ json: { choices: [{ message: { content } }], api_used: model } }];
  } else {
    // ✅ IMPROVED: Check for safety blocking as the reason for no candidates
    if (response.promptFeedback && response.promptFeedback.blockReason) {
      const reason = response.promptFeedback.blockReason;
      console.log(`❌ Request blocked by safety filters. Reason: ${reason}`);
      return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], error: `Blocked by safety filter: ${reason}`, api_used: 'error' } }];
    } else {
      console.log('❌ No candidates in Gemini response for an unknown reason.');
      console.log('🔍 Full response for debugging:', JSON.stringify(response, null, 2));
      return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], error: 'No candidates in response', api_used: 'error' } }];
    }
  }

} catch (error) {
  console.log('❌ Gemini API Error:', error.message);

  // Enhanced error handling per user feedback
  if (error.message.includes('429') || error.message.includes('quota')) {
    console.log('⚠️ Quota exceeded - this is expected on free tier');
    console.log('💡 Solution: Wait 5-10 minutes or upgrade billing plan');
  }

  console.log('📊 Error Details:', JSON.stringify(error, null, 2));

  // Return default values on error
  return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], error: error.message, api_used: 'error' } }];
}

// Get the detection result from Detect OCEAN node
const det = $input.first()?.json || {};
const raw = det?.choices?.[0]?.message?.content ?? '';

// Get the session data from the previous workflow execution items
const ingestData = $items('Ingest (Per-turn, no smoothing)', 'main', 0)?.json || {};

// Debug: Check all available items
console.log('Parse Detection - All available items:', JSON.stringify($items()));
console.log('Parse Detection - Ingest items specifically:', JSON.stringify($items('Ingest (Per-turn, no smoothing)')));

console.log('Parse Detection - Detection result:', JSON.stringify(det));
console.log('Parse Detection - Ingest data:', JSON.stringify(ingestData));
console.log('Parse Detection - Raw API response content:', raw);

let parsed = {};
try {
  // First try to parse the raw content directly
  parsed = JSON.parse(raw);
} catch (e) {
  // If that fails, try to extract JSON from the content
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      console.log('Failed to parse extracted JSON:', e2.message);
      parsed = {};
    }
  } else {
    console.log('No JSON found in content:', raw);
  }
}

console.log('Parse Detection - Parsed object:', JSON.stringify(parsed));

// Extract OCEAN discrete values
let oceanDisc = parsed?.ocean_disc;

// If ocean_disc doesn't exist but ocean does, convert continuous to discrete
if (!oceanDisc && parsed?.ocean) {
  const thr = 0.2;
  const o = parsed.ocean;
  const sign = (v) => (v >= thr ? 1 : (v <= -thr ? -1 : 0));
  oceanDisc = {
    O: sign(o.O || 0),
    C: sign(o.C || 0), 
    E: sign(o.E || 0),
    A: sign(o.A || 0),
    N: sign(o.N || 0)
  };
}

// Ensure we have a valid oceanDisc object
const od = oceanDisc || { O: 0, C: 0, E: 0, A: 0, N: 0 };

// Extract session data from ingest
const turnText = ingestData?.clean_msg || '';
const sessionId = ingestData?.session_id || '';

console.log('Parse Detection - Final ocean_disc values:', JSON.stringify(od));
console.log('Parse Detection - Session ID:', sessionId);
console.log('Parse Detection - Turn text:', turnText);

return [{
  json: {
    ocean_disc: od,
    turn_text: turnText,
    session_id: sessionId
  }
}];

