// ENHANCED: Gemini API with Safety Filter Detection for Response Generation
const GEMINI_API_KEY = 'AIzaSyCu7cMyJAB4ossEePGYQQGpzjlqAfbIG2E';

// Extract all data from the regulation input
const inputData = $input.first()?.json || {};
const directives = inputData?.directives || [];
const sessionId = inputData?.session_id || '';
const turnText = inputData?.turn_text || '';
const oceanDisc = inputData?.ocean_disc || { O:0, C:0, E:0, A:0, N:0 };

console.log('Generate Response - Input data:', JSON.stringify(inputData));
console.log('Generate Response - Ocean disc:', JSON.stringify(oceanDisc));
console.log('Generate Response - Session ID:', sessionId);
console.log('Generate Response - Turn text:', turnText);
console.log('Generate Response - Directives:', JSON.stringify(directives));

let userText = turnText.trim();
if (!userText) {
  userText = 'Please provide a supportive, grounded reply to the user. Context provided separately.';
}

const systemPrompt = [
  'You are a supportive assistant. Follow these behavior directives strictly:',
  JSON.stringify(directives),
  'Constraints: stay grounded in the user text only; 1-2 questions max; 70-150 words.'
].join(' ');

const fullPrompt = `${systemPrompt}\n\nUser: ${userText}`;

console.log('🚀 Calling Gemini API for response generation...');
console.log('📝 System prompt:', systemPrompt.substring(0, 150) + '...');
console.log('👤 User text:', userText.substring(0, 100) + (userText.length > 100 ? '...' : ''));

// ✅ CORRECTED: Using recommended model for reliability
const model = 'gemini-1.5-flash-latest';
const options = {
  method: 'POST',
  url: `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${GEMINI_API_KEY}`,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ // ✅ User's suggestion: explicit JSON.stringify
    contents: [{ parts: [{ text: fullPrompt }] }],
    generationConfig: { 
      temperature: 0.7, 
      maxOutputTokens: 220, 
      topK: 40, 
      topP: 0.95 
    },
    safetySettings: [
      { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
      { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
      { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
      { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' }
    ]
  }),
  timeout: 20000
};

try {
  const response = await this.helpers.httpRequest(options);

  console.log('📊 Raw Gemini Response:', JSON.stringify(response, null, 2));

  // ✅ IMPROVED: Check for candidates first
  if (response.candidates && response.candidates.length > 0) {
    const content = response.candidates[0].content.parts[0].text;
    console.log('✅ Gemini API response generation successful');
    console.log('📝 Generated content:', content.substring(0, 150) + (content.length > 150 ? '...' : ''));

    return {
      json: {
        choices: [{ message: { content } }],
        session_id: sessionId,
        turn_text: turnText,
        ocean_disc: oceanDisc,
        directives: directives,
        api_used: model
      }
    };
  } else {
    // ✅ IMPROVED: Check for safety blocking as the reason for no candidates
    if (response.promptFeedback && response.promptFeedback.blockReason) {
      const reason = response.promptFeedback.blockReason;
      console.log(`❌ Response generation blocked by safety filters. Reason: ${reason}`);
      return {
        json: {
          choices: [{ message: { content: `Sorry—response was blocked by safety filters (${reason}). Quick tip: take 3 slow breaths and exhale longer than you inhale.` } }],
          error: `Blocked by safety filter: ${reason}`,
          session_id: sessionId,
          turn_text: turnText,
          ocean_disc: oceanDisc,
          directives: directives,
          api_used: 'error'
        }
      };
    } else {
      console.log('❌ No candidates in Gemini response for an unknown reason.');
      console.log('🔍 Full response for debugging:', JSON.stringify(response, null, 2));
      return {
        json: {
          choices: [{ message: { content: 'Sorry—response generation is temporarily unavailable. Quick tip: take 3 slow breaths and exhale longer than you inhale.' } }],
          error: 'No candidates in response',
          session_id: sessionId,
          turn_text: turnText,
          ocean_disc: oceanDisc,
          directives: directives,
          api_used: 'error'
        }
      };
    }
  }

} catch (error) {
  console.log('❌ Gemini API Error:', error.message);

  // Enhanced error handling per user feedback
  if (error.message.includes('429') || error.message.includes('quota')) {
    console.log('⚠️ Quota exceeded - this is expected on free tier');
    console.log('💡 Solution: Wait 5-10 minutes or upgrade billing plan');
  }

  console.log('📊 Error Details:', JSON.stringify(error, null, 2));

  // Return fallback response on error
  return {
    json: {
      choices: [{ message: { content: 'Sorry—response generation encountered an error. Quick tip: take 3 slow breaths and exhale longer than you inhale.' } }],
      error: error.message,
      session_id: sessionId,
      turn_text: turnText,
      ocean_disc: oceanDisc,
      directives: directives,
      api_used: 'error'
    }
  };
}

